import urllib.request
import urllib.error
import json
import re
import sys
import os
from datetime import datetime

# 设置输出编码
sys.stdout.reconfigure(encoding='utf-8')

# ============ 配置区域 ============

# 飞书配置
FEISHU_APP_ID = "cli_a924c3fc05f89cee"
FEISHU_APP_SECRET = "43MXrfLFa7sORlI3aMapEdG0aHVJqZ3E"
