}

# 文件路径
WORKSPACE = r"C:\Users\zyc\.nanobot\workspace"
HISTORY_FILE = os.path.join(WORKSPACE, "finance_news_history.json")
OUTPUT_FILE = os.path.join(WORKSPACE, "finance_news_for_feishu.json")

# ============ 飞书 API 工具 ============

def get_feishu_token():
    """获取飞书 tenant_access_token"""
    url = "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal"
    payload = {
        "app_id": FEISHU_APP_ID,
        "app_secret": FEISHU_APP_SECRET
    }

    try:
        data = json.dumps(payload).encode('utf-8')
        req = urllib.request.Request(
            url,
            data=data,
            headers={'Content-Type': 'application/json'}
        )
        with urllib.request.urlopen(req, timeout=10) as response:
            result = json.loads(response.read().decode('utf-8'))
            if result.get('code') == 0:
                return result.get('tenant_access_token')
            else:
                print(f"❌ 获取飞书 Token 失败：{result}")
                return None
    except Exception as e:
        print(f"❌ 飞书 API 异常：{e}")
        return None

def send_feishu_message(content):
    """发送飞书群消息"""
    token = get_feishu_token()
    if not token:
        return False

    url = "https://open.feishu.cn/open-apis/im/v1/messages"

    # 使用交互式卡片消息
    payload = {
        "receive_id": FEISHU_GROUP_CHAT_ID,
        "msg_type": "interactive",
        "content": json.dumps({
            "config": {
                "wide_screen_mode": True
            },
            "header": {
                "template": "blue",
                "title": {
                    "content": "📰 财经快讯监控",
                    "tag": "plain_text"
                }
            },
            "elements": [
                {
                    "tag": "markdown",
                    "content": content
                },
                {
                    "tag": "hr"
                },
                {
                    "tag": "note",
                    "elements": [
                        {
                            "tag": "plain_text",
                            "content": "💡 监控频率：每 30 分钟 | 关键词：AI/芯片/港股/宏观/公司"
                        }
                    ]
                }
            ]
        })
    }

    try:
        data = json.dumps(payload).encode('utf-8')
        req = urllib.request.Request(
            url,
            data=data,
            headers={
                'Content-Type': 'application/json',
                'Authorization': f'Bearer {token}'
            }
        )
        with urllib.request.urlopen(req, timeout=10) as response:
            result = json.loads(response.read().decode('utf-8'))
            if result.get('code') == 0:
                print("✅ 飞书推送成功")
                return True
            else:
                print(f"❌ 飞书推送失败：{result}")
                return False
    except Exception as e:
        print(f"❌ 飞书推送异常：{e}")
        return False

# ============ 监控工具 ============

def load_history():
    """加载已推送消息历史"""
    try:
        with open(HISTORY_FILE, 'r', encoding='utf-8') as f:
            return json.load(f)
    except:
        return {"sent_ids": [], "last_check": None}

def save_history(history):
    """保存已推送消息历史"""
    with open(HISTORY_FILE, 'w', encoding='utf-8') as f:
        json.dump(history, f, ensure_ascii=False, indent=2)

def fetch_cls_telegraph():
    """抓取财联社电报"""
    url = "https://www.cls.cn/telegraph"
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
        'Accept-Language': 'zh-CN,zh;q=0.9,en;q=0.8',
    }

    try:
        req = urllib.request.Request(url, headers=headers)
        with urllib.request.urlopen(req, timeout=15) as response:
            html = response.read().decode('utf-8')
            return parse_cls_content(html)
    except Exception as e:
        print(f"❌ 财联社抓取失败：{e}")
        return []

def parse_cls_content(html):
    """解析财联社内容"""
    news_list = []

    # 尝试多种模式匹配
    patterns = [
        r'(\d{2}:\d{2}:\d{2})\s*财联社 (.*?)(?=\d{2}:\d{2}:\d{2}\s*财联社|$)',
        r'(\d{2}:\d{2}:\d{2})\s*【(.*?)】',
        r'(\d{2}:\d{2}:\d{2}.*?电，.*?)'
    ]

    for pattern in patterns:
        matches = re.findall(pattern, html, re.DOTALL)
        if matches:
            for match in matches:
                if isinstance(match, tuple):
                    time_str = match[0] if len(match) > 0 else ""
                    content = match[1] if len(match) > 1 else match[0]
                else:
                    time_str = ""
                    content = match

                content = re.sub(r'<[^>]+>', '', content)  # 清理 HTML 标签
                content = re.sub(r'\s+', ' ', content).strip()

                if len(content) > 15 and '财联社' in content:
                    news_id = f"cls_{len(news_list)}_{hash(content) % 10000}"
                    news_list.append({
                        "id": news_id,
                        "content": content,
                        "source": "财联社",
                        "time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                    })

            if news_list:
                break

    # 去重并限制数量
    seen = set()
    unique_news = []
    for news in news_list:
        if news['content'] not in seen:
            seen.add(news['content'])
            unique_news.append(news)

    return unique_news[:30]

def match_keywords(content):
    """匹配关键词，返回匹配的类别"""
    matched = []
    content_lower = content.lower()
    for category, keywords in KEYWORDS.items():
        for keyword in keywords:
            if keyword.lower() in content_lower:
                matched.append(category)
                break
    return list(set(matched))

def format_message(news_list):
    """格式化飞书消息内容"""
    lines = []
    lines.append(f"**📰 财经快讯监控**")
    lines.append(f"_更新时间：{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}_\n")

    for i, news in enumerate(news_list, 1):
        categories = news.get('categories', [])

        # 根据类别添加图标和优先级
        if 'AI 大模型' in categories:
            icon = "🤖"
            priority = "🔴"
        elif '公司动态' in categories:
            icon = "🏢"
            priority = "🟡"
        elif '宏观经济' in categories:
            icon = "📊"
            priority = "🟡"
        elif '股市期货' in categories:
            icon = "📈"
            priority = "🟢"
        else:
            icon = "📰"
            priority = "⚪"

        content = news.get('content', '')
        # 清理过长的内容
        if len(content) > 200:
            content = content[:200] + "..."

        lines.append(f"{priority} {icon} **{i}. {content}**")
        lines.append("")

    return "\n".join(lines)

# ============ 主函数 ============

def main():
    print("=" * 60)
    print("📈 财经快讯监控 + 推送")
    print(f"⏰ 执行时间：{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 60)

    # 加载历史
    history = load_history()
    sent_ids = history.get("sent_ids", [])

    # 抓取新闻
    print("\n📡 正在抓取财联社...")
    cls_news = fetch_cls_telegraph()
    print(f"📰 抓取到 {len(cls_news)} 条快讯")

    # 过滤已推送的
    new_news = [n for n in cls_news if n["id"] not in sent_ids]
    print(f"✨ 新消息：{len(new_news)} 条")

    # 匹配关键词
    matched_news = []
    for news in new_news:
        categories = match_keywords(news["content"])
        if categories:
            news["categories"] = categories
            matched_news.append(news)

    print(f"🎯 匹配关键词：{len(matched_news)} 条")

    # 推送消息
    if matched_news:
        # 格式化消息
        message = format_message(matched_news)

        print("\n" + message)
        print("\n" + "=" * 60)

        # 发送到飞书
        print("\n📤 正在推送到飞书群...")
        success = send_feishu_message(message)

        if success:
            # 更新历史
            for news in matched_news:
                sent_ids.append(news["id"])
            history["sent_ids"] = sent_ids[-500:]  # 保留最近 500 条
            history["last_check"] = datetime.now().isoformat()
            save_history(history)

            # 输出 JSON 供参考
            output = {
                "has_news": True,
                "count": len(matched_news),
                "pushed_at": datetime.now().isoformat(),
                "news": matched_news
            }
            with open(OUTPUT_FILE, 'w', encoding='utf-8') as f:
                json.dump(output, f, ensure_ascii=False, indent=2)

            print(f"\n✅ 完成！推送 {len(matched_news)} 条消息")
        else:
            print("\n❌ 推送失败，请检查飞书配置")
    else:
        print("\n⏭️ 没有新的匹配消息")

        # 输出空结果
        output = {
            "has_news": False,
            "count": 0,
            "checked_at": datetime.now().isoformat()
        }
        with open(OUTPUT_FILE, 'w', encoding='utf-8') as f:
            json.dump(output, f, ensure_ascii=False, indent=2)

    print("\n" + "=" * 60)

if __name__ == "__main__":
    main()
